        // Segment 2: user + assistant
        assert_eq!(segments.len(), 2);
        assert_eq!(segments[0].entries.len(), 1);
        assert_eq!(segments[1].entries.len(), 2);
    }

    #[test]
    fn group_empty_entries() {
        let segments = group_into_segments(&[]);
        assert!(segments.is_empty());
